bool isValid(const vector<int> &A, int D, int T) {
    long long sum = 0;
    for (int num : A) {
        sum += (num + D - 1) / D; // Equivalent to ceil(num / D)
        if (sum > T) return false; // Early exit
    }
    return true;
}

// Function to find the smallest divisor
int findSmallestDivisor(const vector<int> &A, int T) {
    int left = 1;
    int right = *max_element(A.begin(), A.end());
    int ans = right;

    while (left <= right) {
        int mid = left + (right - left) / 2;
        if (isValid(A, mid, T)) {
            ans = mid;       // Update answer
            right = mid - 1; // Try smaller divisor
        } else {
            left = mid + 1;  // Increase divisor
        }
    }

    return ans;
}

