int isValid(int A[], int N, int D, int T) {
    long long sum = 0;
    for (int i = 0; i < N; i++) {
        sum += (A[i] + D - 1) / D;  // Equivalent to ceil(A[i]/D)
        if (sum > T) return 0;      // Early exit if sum exceeds T
    }
    return 1; // Valid
}

// Function to find the smallest divisor
int findSmallestDivisor(int A[], int N, int T) {
    int left = 1;
    int right = A[0];

    // Find the maximum element in the array
    for (int i = 1; i < N; i++) {
        if (A[i] > right) right = A[i];
    }

    int ans = right;

    while (left <= right) {
        int mid = left + (right - left) / 2;
        if (isValid(A, N, mid, T)) {
            ans = mid;       // Update answer
            right = mid - 1; // Try smaller divisor
        } else {
            left = mid + 1;  // Increase divisor
        }
    }

    return ans;
}

