   public static int findSmallestDivisor(int[] A, int T) {
       int left = 1; // Minimum possible divisor
       int right = Arrays.stream(A).max().getAsInt(); // Maximum element in array
       int ans = right;

       while (left <= right) {
           int mid = left + (right - left) / 2;

           if (isValid(A, mid, T)) {
               ans = mid;       // Update answer
               right = mid - 1; // Try smaller divisor
           } else {
               left = mid + 1;  // Increase divisor
           }
       }

       return ans;
   }

